                <script type="text/javascript">
                    $('input[name="daterange"]').daterangepicker(
                        {
                            opens: "left",
                            locale: {
                                format: "DD/MM/YYYY",
                            },
                        },
                        function (start, end, label) {
                            // console.log("A new date selection was made: " + start.format('YYYY-MM-DD') + ' to ' + end.format('YYYY-MM-DD'));
                            var startdate = start.format("YYYY-MM-DD");
                            var enddate = end.format("YYYY-MM-DD");
                            //console.log(startdate);
                            //console.log(enddate);

                            getChartDatadate(startdate, enddate);
                        }
                    );

                    function Action_Function() {
                        document.getElementById("myDropdown").classList.toggle("show");
                    }

                    // Close the dropdown if the user clicks outside of it
                    window.onclick = function (event) {
                        if (!event.target.matches(".dropbtn")) {
                            var dropdowns = document.getElementsByClassName("dropdown-content");
                            var i;
                            for (i = 0; i < dropdowns.length; i++) {
                                var openDropdown = dropdowns[i];
                                if (openDropdown.classList.contains("show")) {
                                    openDropdown.classList.remove("show");
                                }
                            }
                        }
                    };

                    function openRightMenu() {
                        // document.getElementById("rightsidebar").style.display = "block";

                        var rightsidebar = document.getElementById("rightsidebar");
                        var leftcontent = document.getElementById("leftcontent");

                        if (rightsidebar.style.display === "block") {
                            rightsidebar.style.display = "none";
                            // console.log('t');
                            document.getElementById("myImage").src = "http://localhost:8090/MOAIDB/callcenter/assets/images/icons/icon_chevronsleft.png";
                            $(".btndbactive").removeClass("active");
                            leftcontent.style.marginRight = "0%";
                            rightsidebar.style.width = "350px";
                            document.getElementById("pinimg").src = "http://localhost:8090/MOAIDB/callcenter/assets/images/icons/pin_01_grey.png";
                        } else {
                            rightsidebar.style.display = "block";
                            // console.log('e');
                            document.getElementById("myImage").src = "http://localhost:8090/MOAIDB/callcenter/assets/images/icons/chevronsright_orange.png";
                            $(".btndbactive").addClass("active");
                        }
                    }

                    function pinRightMenu() {
                        var rightsidebar = document.getElementById("rightsidebar");
                        var leftcontent = document.getElementById("leftcontent");

                        if (leftcontent.style.marginRight == "15%") {
                            leftcontent.style.marginRight = "0%";
                            rightsidebar.style.width = "350px";
                            // console.log('t');
                            document.getElementById("pinimg").src = "http://localhost:8090/MOAIDB/callcenter/assets/images/icons/pin_01_grey.png";
                        } else {
                            leftcontent.style.marginRight = "15%";
                            rightsidebar.style.width = "15%";
                            document.getElementById("pinimg").src = "http://localhost:8090/MOAIDB/callcenter/assets/images/icons/pin_02_orange.png";
                        }
                    }
                </script>

                <script>
                    const grid_width = 3;
